The following Dafny program has a correct implementation and specification, but verification fails because some `assert` statements are missing. The program verified successfully before these assertions were removed.

RULES — read carefully:
1. Add `assert` statements to make `dafny verify` pass.
2. You may add helper lemmas or ghost functions if needed.
3. You MUST NOT modify ANY existing code. Do not change variable names, assignments, control flow, loop bodies, if/else branches, return statements, or any expression.
4. You MUST NOT modify ANY formal specification. Do not change requires, ensures, invariant, decreases, function bodies, or predicate bodies.
5. Any modification to existing code or specifications will be automatically detected and rejected. We compare the AST of your output against the original — only added assert statements and new lemma/function definitions are permitted.

Return the complete Dafny program with your added assertions inside <DAFNY_CODE> tags.

```dafny
ghost function MaxOf(a: int, b: int): int {
  if a > b then a else b
}

ghost function MinOf(a: int, b: int): int {
  if a < b then a else b
}

// A valid solution: positive a, b, c whose pairwise maxima are exactly x, y, z
ghost predicate IsValidSolution(x: int, y: int, z: int, a: int, b: int, c: int) {
  a > 0 && b > 0 && c > 0 &&
  MaxOf(a, b) == x && MaxOf(a, c) == y && MaxOf(b, c) == z
}

// Does any valid solution exist?
ghost predicate SolutionExists(x: int, y: int, z: int)
  requires x > 0 && y > 0 && z > 0
{
  exists a ::
    exists b ::
      exists c ::
        IsValidSolution(x, y, z, a, b, c)
}

method ThreePairwiseMaximums(x: int, y: int, z: int) returns (possible: bool, a: int, b: int, c: int)
  requires x > 0 && y > 0 && z > 0
  ensures possible == SolutionExists(x, y, z)
  ensures possible ==> IsValidSolution(x, y, z, a, b, c)
{
  var m := x;
  if y > m { m := y; }
  if z > m { m := z; }

  var cnt := 0;
  if x == m { cnt := cnt + 1; }
  if y == m { cnt := cnt + 1; }
  if z == m { cnt := cnt + 1; }

  if cnt >= 2 {
    possible := true;
    a := if x <= y then x else y;
    b := if x <= z then x else z;
    c := if y <= z then y else z;

  } else {
    possible := false;
    a := 0;
    b := 0;
    c := 0;
    // cnt == 1: exactly one of x,y,z equals m = max(x,y,z)
    // Key insight: the largest of any a',b',c' appears in at least 2 pairwise maxima,
    // so the max of x,y,z must appear at least twice. Contradiction with cnt < 2.
    forall a': int, b': int, c': int
      ensures !IsValidSolution(x, y, z, a', b', c')
    {
      if a' > 0 && b' > 0 && c' > 0 && MaxOf(a', b') == x && MaxOf(a', c') == y && MaxOf(b', c') == z {
        if a' >= b' && a' >= c' {
          // a' is largest: MaxOf(a',b')=a'=x, MaxOf(a',c')=a'=y, so x==y
          // z = MaxOf(b',c') <= a' = x, so m = max(x,y,z) = x = y
          // Both x==m and y==m, so cnt >= 2, contradiction
          assert MaxOf(a', b') == a';
          assert MaxOf(a', c') == a';
          assert x == a' && y == a';
        } else if b' >= a' && b' >= c' {
          // b' is largest: MaxOf(a',b')=b'=x, MaxOf(b',c')=b'=z, so x==z
          assert MaxOf(a', b') == b';
          assert MaxOf(b', c') == b';
          assert x == b' && z == b';
        } else {
          // c' is largest: MaxOf(a',c')=c'=y, MaxOf(b',c')=c'=z, so y==z
          assert c' >= a' && c' >= b';
          assert MaxOf(a', c') == c';
          assert MaxOf(b', c') == c';
          assert y == c' && z == c';
        }
      }
    }
  }
}

```

